// TestQueryCapabilityProvider_RealUsagePattern tests that a component can
// implement QueryCapabilityProvider and return valid capabilities
func TestQueryCapabilityProvider_RealUsagePattern(t *testing.T) {
	// Simulate a real component implementing the interface
	component := &mockQueryProvider{
		component: "graph-ingest",
		version:   "1.0.0",
		queries: []QueryCapability{
			{
				Subject:        "graph.ingest.query.entity",
				Operation:      "getEntity",
				Description:    "Get single entity by ID",
				RequestSchema:  map[string]any{"type": "object", "properties": map[string]any{"id": map[string]any{"type": "string"}}},
				ResponseSchema: map[string]any{"$ref": "#/definitions/EntityState"},
			},
			{
				Subject:        "graph.ingest.query.batch",
				Operation:      "getBatch",
				Description:    "Get multiple entities by IDs",
				RequestSchema:  map[string]any{"type": "object", "properties": map[string]any{"ids": map[string]any{"type": "array"}}},
				ResponseSchema: map[string]any{"type": "array"},
			},
		},
		definitions: map[string]any{
			"EntityState": map[string]any{
				"type": "object",
				"properties": map[string]any{
					"entityID": map[string]any{"type": "string"},
					"triples":  map[string]any{"type": "array"},
				},
			},
		},
	}

	// Type assertion to QueryCapabilityProvider
	provider, ok := interface{}(component).(QueryCapabilityProvider)
	if !ok {
		t.Fatal("mockQueryProvider should implement QueryCapabilityProvider")
	}

	// Get capabilities
	capabilities := provider.QueryCapabilities()

	// Verify structure
	if capabilities.Component != "graph-ingest" {
		t.Errorf("Expected component 'graph-ingest', got '%s'", capabilities.Component)
	}
	if capabilities.Version != "1.0.0" {
		t.Errorf("Expected version '1.0.0', got '%s'", capabilities.Version)
	}
	if len(capabilities.Queries) != 2 {
		t.Fatalf("Expected 2 queries, got %d", len(capabilities.Queries))
	}

	// Verify first query
	q1 := capabilities.Queries[0]
	if q1.Subject != "graph.ingest.query.entity" {
		t.Errorf("Expected subject 'graph.ingest.query.entity', got '%s'", q1.Subject)
	}
	if q1.Operation != "getEntity" {
		t.Errorf("Expected operation 'getEntity', got '%s'", q1.Operation)
	}

	// Verify second query
	q2 := capabilities.Queries[1]
	if q2.Subject != "graph.ingest.query.batch" {
		t.Errorf("Expected subject 'graph.ingest.query.batch', got '%s'", q2.Subject)
	}

	// Verify definitions
	if len(capabilities.Definitions) != 1 {
		t.Errorf("Expected 1 definition, got %d", len(capabilities.Definitions))
	}

	// Verify JSON serialization of full response
	jsonData, err := json.Marshal(capabilities)
	if err != nil {
		t.Fatalf("Failed to marshal capabilities: %v", err)
	}

	var unmarshaled QueryCapabilities
	if err := json.Unmarshal(jsonData, &unmarshaled); err != nil {
		t.Fatalf("Failed to unmarshal capabilities: %v", err)
	}

	if unmarshaled.Component != capabilities.Component {
		t.Errorf("Component mismatch after JSON round-trip")
	}
	if len(unmarshaled.Queries) != len(capabilities.Queries) {
		t.Errorf("Queries count mismatch after JSON round-trip")
	}
}

// TestQueryCapabilityProvider_DiscoveryPattern tests the discovery pattern
// where a coordinator can type-assert and discover capabilities
func TestQueryCapabilityProvider_DiscoveryPattern(t *testing.T) {
	// Simulate multiple components, some with query capabilities, some without
	components := []interface{}{
		&mockQueryProvider{
			component: "graph-ingest",
			version:   "1.0.0",
			queries: []QueryCapability{
				{
					Subject:        "graph.ingest.query.entity",
					Operation:      "getEntity",
					RequestSchema:  map[string]any{},
					ResponseSchema: map[string]any{},
				},
			},
		},
		&mockNonQueryProvider{}, // Doesn't implement QueryCapabilityProvider
		&mockQueryProvider{
			component: "graph-index",
			version:   "1.0.0",
			queries: []QueryCapability{
				{
					Subject:        "graph.index.query.outgoing",
					Operation:      "getOutgoing",
					RequestSchema:  map[string]any{},
					ResponseSchema: map[string]any{},
				},
			},
		},
	}

	// Discovery logic (what graph-query coordinator would do)
	var discoveredCapabilities []QueryCapabilities
	for _, comp := range components {
		if provider, ok := comp.(QueryCapabilityProvider); ok {
			caps := provider.QueryCapabilities()
			discoveredCapabilities = append(discoveredCapabilities, caps)
		}
	}

	// Should discover 2 components with query capabilities
	if len(discoveredCapabilities) != 2 {
		t.Fatalf("Expected to discover 2 components with query capabilities, got %d", len(discoveredCapabilities))
	}

	// Verify discovered components
	if discoveredCapabilities[0].Component != "graph-ingest" {
		t.Errorf("Expected first discovered component 'graph-ingest', got '%s'", discoveredCapabilities[0].Component)
	}
	if discoveredCapabilities[1].Component != "graph-index" {
		t.Errorf("Expected second discovered component 'graph-index', got '%s'", discoveredCapabilities[1].Component)
	}
}

